def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0.0
        weight = 1.0
        penalty = 0.0
        bonus = 0.0
        for j in range(1, 15):
            if j % 3 == 0:
                weight *= 0.85
            if ratio < (0.04 * j) and j % 2 == 0:
                score += (j ** 2) * (1 - ratio)**3 * weight
                if cap % (j+2) == 0:
                    score += np.log1p(j) * 1.5
                else:
                    score -= np.sqrt(j) * 0.8
            elif ratio < 0.8:
                score += j * np.exp(-ratio * j * 1.1) * weight / (j+2)
                if (cap + j*2) % 5 == 0:
                    score += np.sin(ratio * j * 1.2) * 2
                else:
                    score -= np.cos(ratio * j * 0.9)
            else:
                score -= j * ratio**1.5 * weight
            if j % 4 == 1:
                bonus += np.tanh(score / (j + 2)) * 0.9
            elif j % 4 == 2:
                penalty += np.arctan(score / (j + 3)) * 0.6
            elif j % 4 == 3:
                bonus -= np.tanh(score / (j + 1)) * 1.1
            else:
                penalty -= np.arctan(score / (j + 4)) * 0.7
        for k in range(1, 7):
            residual = cap - item * k
            if residual > 0:
                if residual % (k + 1) == 0:
                    score += np.log1p(residual) / (k + 0.3)
                    bonus += np.sqrt(residual) / (k + 0.5)
                else:
                    score -= (residual ** 0.33) / (k + 1.7)
                    penalty += (residual ** 0.25) / (k + 2)
            else:
                score -= abs(residual) * 0.15 * k
                penalty += abs(residual)**0.5 * 0.2 * k
        complexity_factor = np.tanh((score + bonus - penalty) / (cap + 2))
        if complexity_factor > 0.5:
            priorities[i] = -complexity_factor * np.exp(-ratio * 0.7) * (np.log1p(cap) + np.log1p(item))
        elif complexity_factor > 0:
            priorities[i] = -complexity_factor * (np.sqrt(cap) + np.cbrt(item))
        else:
            priorities[i] = -complexity_factor * (np.sin(cap * ratio) + np.cos(item / (cap+1)))
        if priorities[i] == 0:
            priorities[i] = np.inf
    return priorities
